from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
from typing import List, Optional
import sqlite3
import os

app = FastAPI(title="Todo API")

DB_PATH = os.path.join(os.path.dirname(__file__), "todos.db")

def init_db():
    conn = sqlite3.connect(DB_PATH)
    conn.execute("CREATE TABLE IF NOT EXISTS todos (id INTEGER PRIMARY KEY, title TEXT, completed BOOLEAN)")
    conn.close()

class Todo(BaseModel):
    id: Optional[int] = None
    title: str
    completed: bool = False

class TodoCreate(BaseModel):
    title: str

@app.on_event("startup")
def on_startup():
    init_db()

@app.get("/todos", response_model=List[Todo])
def list_todos():
    conn = sqlite3.connect(DB_PATH)
    cursor = conn.execute("SELECT id, title, completed FROM todos")
    todos = [Todo(id=row[0], title=row[1], completed=bool(row[2])) for row in cursor.fetchall()]
    conn.close()
    return todos

@app.post("/todos", response_model=Todo, status_code=201)
def create_todo(todo: TodoCreate):
    conn = sqlite3.connect(DB_PATH)
    cursor = conn.execute("INSERT INTO todos (title, completed) VALUES (?, ?)", (todo.title, False))
    conn.commit()
    new_id = cursor.lastrowid
    conn.close()
    return Todo(id=new_id, title=todo.title, completed=False)

@app.get("/todos/{todo_id}", response_model=Todo)
def get_todo(todo_id: int):
    conn = sqlite3.connect(DB_PATH)
    cursor = conn.execute("SELECT id, title, completed FROM todos WHERE id = ?", (todo_id,))
    row = cursor.fetchone()
    conn.close()
    if row is None:
        raise HTTPException(status_code=404, detail="Todo not found")
    return Todo(id=row[0], title=row[1], completed=bool(row[2]))

@app.put("/todos/{todo_id}", response_model=Todo)
def update_todo(todo_id: int, todo: TodoCreate):
    conn = sqlite3.connect(DB_PATH)
    cursor = conn.execute("SELECT id, title, completed FROM todos WHERE id = ?", (todo_id,))
    row = cursor.fetchone()
    if row is None:
        conn.close()
        raise HTTPException(status_code=404, detail="Todo not found")
    conn.execute("UPDATE todos SET title = ? WHERE id = ?", (todo.title, todo_id))
    conn.commit()
    conn.close()
    return Todo(id=todo_id, title=todo.title, completed=bool(row[2]))

@app.delete("/todos/{todo_id}", status_code=204)
def delete_todo(todo_id: int):
    conn = sqlite3.connect(DB_PATH)
    cursor = conn.execute("DELETE FROM todos WHERE id = ?", (todo_id,))
    conn.commit()
    deleted = cursor.rowcount > 0
    conn.close()
    if not deleted:
        raise HTTPException(status_code=404, detail="Todo not found")
    return None
